const basename = "/";

const App = () => (
    <ThemeProvider defaultTheme="dark" storageKey="app-theme">
        <AuthProvider>
            <TooltipProvider>
                <Toaster />
                <Sonner />
                <BrowserRouter basename={basename}>
                    <Layout appName="Relay Swap" showHeader={false}>
                    	<RouteSync />
